-- Reparent to match real geography (and the drill-down UX): the four commune
-- AOCs are enclaves inside the Haut-Medoc zone, and Barsac lies within the
-- Sauternes appellation. Levels stay APPELLATION; only the tree depth changes.
update wine_map_nodes set parent_id = (select id from wine_map_nodes where slug = 'haut-medoc')
  where slug in ('saint-estephe', 'pauillac', 'saint-julien', 'margaux');
update wine_map_nodes set parent_id = (select id from wine_map_nodes where slug = 'sauternes')
  where slug = 'barsac';
